import { AudioLines, Box, Globe, ShieldUser, Users } from "lucide-react";
import React from "react";

import { SparklesCore } from "@/components/shadcnblocks/sparkles";
import { cn } from "@/lib/utils";

const features = [
  {
    icon: Globe,
    title: "Developer Friendly",
    description:
      "Built with modern technologies and clean APIs for seamless integration.",
  },
  {
    icon: Box,
    title: "Lightning Fast",
    description:
      "Optimized performance with minimal bundle size and instant loading.",
  },
  {
    icon: ShieldUser,
    title: "Secure by Default",
    description:
      "Enterprise-grade security with built-in protection and compliance.",
  },
  {
    icon: Users,
    title: "Team Collaboration",
    description:
      "Built for teams with real-time collaboration and version control.",
  },
  {
    icon: AudioLines,
    title: "Voice Integration",
    description:
      "Advanced audio processing with natural language understanding.",
  },
];

interface Feature294Props {
  className?: string;
}

const Feature294 = ({ className }: Feature294Props) => {
  return (
    <section
      className={cn(
        "dark relative w-screen overflow-hidden bg-background py-32 text-foreground",
        className,
      )}
    >
      <div className="relative container flex h-full flex-col items-center justify-center">
        <div className="w-full max-w-lg text-center">
          <h1 className="relative z-20 text-center text-5xl font-semibold tracking-tighter md:text-6xl lg:text-7xl">
            Features
          </h1>
          <p className="mt-4 text-muted-foreground/50">
            Our features are designed to be easy to use and integrate.
          </p>
        </div>
        <div className="relative mt-5 mb-10 h-40 w-[40rem]">
          {/* Gradients */}
          <div className="absolute inset-x-20 top-0 h-[2px] w-3/4 bg-gradient-to-r from-transparent via-indigo-500 to-transparent blur-sm" />
          <div className="absolute inset-x-20 top-0 h-px w-3/4 bg-gradient-to-r from-transparent via-indigo-500 to-transparent" />
          <div className="absolute inset-x-60 top-0 h-[5px] w-1/4 bg-gradient-to-r from-transparent via-sky-500 to-transparent blur-sm" />
          <div className="absolute inset-x-60 top-0 h-px w-1/4 bg-gradient-to-r from-transparent via-sky-500 to-transparent" />

          {/* Core component */}
          <SparklesCore
            background="transparent"
            minSize={0.4}
            maxSize={1}
            particleDensity={500}
            className="h-full w-full"
            particleColor="#FFFFFF"
          />

          {/* Radial Gradient to prevent sharp edges */}
          <div className="absolute inset-0 h-full w-full bg-background [mask-image:radial-gradient(350px_130px_at_top,transparent_20%,white)]"></div>
        </div>

        <div className="grid w-full max-w-5xl grid-cols-1 gap-15 md:grid-cols-2 lg:grid-cols-3">
          {features.map((feature, index) => {
            const IconComponent = feature.icon;
            return (
              <div key={index} className="flex gap-4">
                <IconComponent className="w-12 stroke-1 text-sky-500" />
                <div className="space-y-2">
                  <h4 className="text-xl font-medium">{feature.title}</h4>
                  <p className="text-muted-foreground/30">
                    {feature.description}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
};

export { Feature294 };

// Modified from Aceternity UI (https://ui.aceternity.com)
// Rewritten to use native Canvas API instead of tsparticles

"use client";
import React, { useRef, useEffect, useId, useCallback, useState } from "react";
import { cn } from "@/lib/utils";

type ParticlesProps = {
  id?: string;
  className?: string;
  background?: string;
  particleSize?: number;
  minSize?: number;
  maxSize?: number;
  speed?: number;
  particleColor?: string;
  particleDensity?: number;
};

interface Particle {
  x: number;
  y: number;
  size: number;
  speedX: number;
  speedY: number;
  opacity: number;
  opacitySpeed: number;
  opacityDirection: number;
}

export const SparklesCore = (props: ParticlesProps) => {
  const {
    id,
    className,
    background = "transparent",
    minSize = 1,
    maxSize = 3,
    speed = 4,
    particleColor = "#ffffff",
    particleDensity = 120,
  } = props;

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const particlesRef = useRef<Particle[]>([]);
  const animationFrameRef = useRef<number>(undefined);
  const generatedId = useId();
  const [isVisible, setIsVisible] = useState(false);

  const createParticle = useCallback(
    (width: number, height: number): Particle => {
      const baseSpeed = speed * 0.02;
      return {
        x: Math.random() * width,
        y: Math.random() * height,
        size: Math.random() * (maxSize - minSize) + minSize,
        speedX: (Math.random() - 0.5) * baseSpeed,
        speedY: (Math.random() - 0.5) * baseSpeed,
        opacity: Math.random(),
        opacitySpeed: (Math.random() * 0.5 + 0.5) * speed * 0.01,
        opacityDirection: Math.random() > 0.5 ? 1 : -1,
      };
    },
    [minSize, maxSize, speed],
  );

  const initParticles = useCallback(
    (width: number, height: number) => {
      // Calculate particle count based on density and area
      const area = width * height;
      const baseArea = 400 * 400;
      const count = Math.floor((particleDensity * area) / baseArea);

      particlesRef.current = Array.from({ length: count }, () =>
        createParticle(width, height),
      );
    },
    [particleDensity, createParticle],
  );

  const hexToRgb = (hex: string): { r: number; g: number; b: number } => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result
      ? {
          r: parseInt(result[1], 16),
          g: parseInt(result[2], 16),
          b: parseInt(result[3], 16),
        }
      : { r: 255, g: 255, b: 255 };
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const rgb = hexToRgb(particleColor);

    const resizeCanvas = () => {
      const rect = container.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;

      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      canvas.style.width = `${rect.width}px`;
      canvas.style.height = `${rect.height}px`;

      ctx.scale(dpr, dpr);

      initParticles(rect.width, rect.height);
    };

    const animate = () => {
      const rect = container.getBoundingClientRect();
      ctx.clearRect(0, 0, rect.width, rect.height);

      particlesRef.current.forEach((particle) => {
        // Update position
        particle.x += particle.speedX;
        particle.y += particle.speedY;

        // Wrap around edges
        if (particle.x < 0) particle.x = rect.width;
        if (particle.x > rect.width) particle.x = 0;
        if (particle.y < 0) particle.y = rect.height;
        if (particle.y > rect.height) particle.y = 0;

        // Update opacity (twinkling effect)
        particle.opacity += particle.opacitySpeed * particle.opacityDirection;
        if (particle.opacity >= 1) {
          particle.opacity = 1;
          particle.opacityDirection = -1;
        } else if (particle.opacity <= 0.1) {
          particle.opacity = 0.1;
          particle.opacityDirection = 1;
        }

        // Draw particle
        ctx.beginPath();
        ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${particle.opacity})`;
        ctx.fill();
      });

      animationFrameRef.current = requestAnimationFrame(animate);
    };

    resizeCanvas();
    animate();

    // Trigger fade in
    requestAnimationFrame(() => setIsVisible(true));

    const resizeObserver = new ResizeObserver(resizeCanvas);
    resizeObserver.observe(container);

    return () => {
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
      resizeObserver.disconnect();
    };
  }, [particleColor, initParticles]);

  return (
    <div
      ref={containerRef}
      className={cn(
        "transition-opacity duration-1000",
        isVisible ? "opacity-100" : "opacity-0",
        className,
      )}
      style={{ background }}
    >
      <canvas
        ref={canvasRef}
        id={id || generatedId}
        className="h-full w-full"
      />
    </div>
  );
};
